if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const authOut = $input.first().json;
const body = authOut.body || authOut;
const docB64 = body.document_b64;
const docName = (body.document_name || '').toLowerCase();
if (!docB64) return $input.all();
const isPdf = docName.endsWith('.pdf');
if (isPdf) {
  return [{ json: { ...authOut, body: { ...body, needs_pdf_extract: true, pdf_b64: docB64, rfp_title: body.rfp_title || body.document_name || 'Uploaded Document' }}}];
}
return $input.all();

const prepOut = $('Prep Input').first().json;
const body = Object.assign({}, prepOut.body || prepOut);
const extraction = $input.first().json;
const extracted = extraction && extraction.content && extraction.content[0] && extraction.content[0].text || '';
if (body.needs_pdf_extract && extracted && extracted !== 'SKIP' && extracted.length > 50) {
  body.rfp_text = extracted;
  body.document_extracted = true;
} else if (body.needs_pdf_extract) {
  body.rfp_text = body.rfp_text || '';
  body.document_extracted = false;
}
delete body.needs_pdf_extract;
delete body.pdf_b64;
return [{ json: { ...prepOut, body } }];

// Try multiple data paths — direct from Auth Guard OR from Merge PDF Extract
var raw = $input.first().json;
var body = raw.body || raw;
// Also check if rfp_text is at the top level (from Merge path)
var rfpText = body.rfp_text || body.rfp_content || body.description || body.content || body.text || raw.rfp_text || '';
var proposalText = body.proposal_text || body.response_text || '';
if (!rfpText && !proposalText) {
  // Last resort: check all upstream nodes
  try { var ab = $('Auth Guard').first().json.body || {}; rfpText = ab.rfp_text || ab.text || ab.content || ''; } catch(e) {}
}
if (!rfpText && !proposalText) {
  return [{ json: { error: true, message: 'Missing content. Upload government documents (RFP/SOW) and/or your proposal response.', timestamp: new Date().toISOString() } }];
}
var agency = body.agency || raw.agency || 'Unknown Agency';
var rfpTitle = body.rfp_title || body.title || raw.rfp_title || 'Untitled RFP';
var solNum = body.solicitation_number || '';
var naics = body.naics || '';
var setAside = body.set_aside || '';
if (rfpText && agency === 'Unknown Agency') { var m = rfpText.match(/(?:Department of|Agency:|Contracting Office:)\s*([^\n]{5,80})/i); if (m) agency = m[1].trim(); }
if (rfpText && !solNum) { var m = rfpText.match(/(?:Solicitation|Sol\.?\s*(?:No|Number|#))\s*[:.]?\s*([A-Z0-9][A-Z0-9\-]{5,30})/i); if (m) solNum = m[1].trim(); }
if (rfpText && !naics) { var m = rfpText.match(/NAICS\s*(?:Code)?\s*[:.]?\s*(\d{6})/i); if (m) naics = m[1]; }
var hasProposal = proposalText.length > 100;
return [{ json: { rfp_text: rfpText, proposal_text: proposalText, mode: hasProposal ? 'comparison' : 'rfp_only', has_proposal: hasProposal, rfp_title: rfpTitle, agency: agency, solicitation_number: solNum, naics: naics, set_aside: setAside, value: body.value || '', file_count: body.file_count || 0, gov_file_names: body.gov_file_names || [], response_file_names: body.response_file_names || [], session_id: body.session_id || ('redteam_' + Date.now()), timestamp: new Date().toISOString() } }];

function parseReview(resp) {
  try {
    const text = resp && resp.content && resp.content[0] ? resp.content[0].text || '' : '';
    if (!text) return { error: 'empty_response' };
    var m = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (m) return JSON.parse(m[1]);
    var s = text.indexOf('{'), e = text.lastIndexOf('}');
    if (s !== -1 && e !== -1) return JSON.parse(text.substring(s, e + 1));
    return JSON.parse(text);
  } catch(e) { return { error: 'parse_failed', raw: (resp && resp.content && resp.content[0] ? resp.content[0].text || '' : '').substring(0, 500) }; }
}
var input = $('Validate RFP Input').first().json;
var pink = parseReview($('Pink Team Review').first().json);
var red = parseReview($('Red Team Review').first().json);
var gold = parseReview($('Gold Team Review').first().json);
var blackhat = parseReview($('Black Hat Review').first().json);
var blue = parseReview($('Blue Team Review').first().json);
var ratings = { pink: pink.pink_team_rating || 'N/A', red: red.red_team_rating || 'N/A', gold: gold.gold_team_rating || 'N/A', blue: blue.blue_team_rating || 'N/A' };
var goNoGo = red.go_no_go || gold.final_go_no_go || 'HOLD';
var winPct = red.win_probability || 'N/A';
var overallRating = red.overall_rating || 'N/A';
var allRecs = [].concat(
  (pink.recommendations || []).map(function(r) { return {text: r, source: 'Pink Team', priority: 'High'}; }),
  (red.recommendations || red.critical_fixes_before_submit || []).map(function(r) { return {text: r, source: 'Red Team', priority: 'Critical'}; }),
  (gold.executive_recommendations || []).map(function(r) { return {text: r, source: 'Gold Team', priority: 'High'}; }),
  (blackhat.counter_strategies || []).map(function(r) { return {text: r, source: 'Black Hat', priority: 'Medium'}; }),
  (blue.critical_fixes || []).map(function(r) { return {text: r, source: 'Blue Team', priority: 'Critical'}; })
);
return [{ json: {
  rfp_title: input.rfp_title, agency: input.agency, solicitation_number: input.solicitation_number || '', naics: input.naics || '', set_aside: input.set_aside || '', mode: input.mode, has_proposal: input.has_proposal, gov_file_names: input.gov_file_names || [], response_file_names: input.response_file_names || [],
  go_no_go: goNoGo, win_probability: winPct, win_probability_rationale: red.win_probability_rationale || '', overall_rating: overallRating, go_confidence: red.go_confidence || 'MEDIUM',
  color_ratings: ratings,
  pink_team: { compliance_matrix: pink.compliance_matrix || [], section_l_compliance: pink.section_l_compliance || [], win_themes: pink.win_themes_assessment || [], structural_issues: pink.structural_issues || [], missing_sections: pink.missing_sections || [], graphics_needed: pink.graphics_needed || [], compliance_score: pink.compliance_score || null, rating: pink.pink_team_rating || 'N/A' },
  red_team: { evaluation_factors: red.evaluation_factors || [], discriminators: red.discriminators || [], competitive_landscape: red.competitive_landscape || '', pricing_insights: red.pricing_insights || '', critical_fixes: red.critical_fixes_before_submit || [], rating: red.red_team_rating || 'N/A' },
  gold_team: { executive_summary: gold.executive_summary || '', win_themes_validated: gold.win_themes_validated || [], discriminators_assessment: gold.discriminators_assessment || [], risk_to_government: gold.risk_to_government || [], price_competitiveness: gold.price_competitiveness || '', narrative_coherence: gold.narrative_coherence || '', submission_readiness: gold.submission_readiness || 'Unknown', rating: gold.gold_team_rating || 'N/A' },
  black_hat: { likely_competitors: blackhat.likely_competitors || [], ghost_themes: blackhat.ghost_themes || [], competitive_positioning: blackhat.competitive_positioning || '', teaming_recommendations: blackhat.teaming_recommendations || [], win_strategy_adjustments: blackhat.win_strategy_adjustments || [] },
  blue_team: { shall_must_will_trace: blue.shall_must_will_trace || [], formatting_issues: blue.formatting_issues || [], deliverables_checklist: blue.deliverables_checklist || [], production_readiness: blue.production_readiness || 'Unknown', conflicting_statements: blue.conflicting_statements || [], rating: blue.blue_team_rating || 'N/A' },
  all_recommendations: allRecs,
  reference_links: [
    {title: 'Shipley Color Team Reviews', url: 'https://www.shipleywins.com/blogs/color-team-reviews'},
    {title: 'FAR 15.305 Proposal Evaluation', url: 'https://www.acquisition.gov/far/15.305'},
    {title: 'FAR 15.308 Source Selection Decision', url: 'https://www.acquisition.gov/far/15.308'},
    {title: 'DoD Source Selection Procedures', url: 'https://www.acq.osd.mil/dpap/policy/policyvault/USA000740-22-DPC.pdf'},
    {title: 'KSI Proposal Color Reviews Guide', url: 'https://info.ksiadvantage.com/blog/articles/gold-at-the-end-of-the-rainbow-proposal-color-reviews-ratings'},
    {title: 'Utley Strategies Pink/Red/Gold Guide', url: 'https://www.utleystrategies.com/blog/pink-red-gold-team-review'},
    {title: 'GDI Consulting Color Team Services', url: 'https://www.gdicwins.com/proposal-color-team-review-services/'}
  ],
  timestamp: new Date().toISOString()
} }];

var agg = $('Aggregate Reviews').first().json;
var resp = $input.first().json;
var draft = (resp && resp.content && resp.content[0] && resp.content[0].text) || '';
return [{ json: Object.assign({}, agg, { draft_response: draft, rewrite_available: !!draft }) }];
